div.script:
(function () {
    const BAF_API = {
        search: '/bestellsystem/part-search',
        addToCart: '/bestellsystem/cart/add',
        upload: '/bestellsystem/upload-parts-list'
    };

    function jsonrpc(url, params) {
        return fetch(url, {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({
                jsonrpc: '2.0',
                method: 'call',
                params: params || {},
                id: Math.floor(Math.random() * 1000000000)
            }),
            credentials: 'same-origin'
        }).then(function (res) {
            if (!res.ok) {
                throw new Error('HTTP ' + res.status);
            }
            return res.json();
        }).then(function (body) {
            if (body.error) {
                throw new Error(body.error.data ? body.error.data.message : body.error.message);
            }
            return body.result;
        });
    }

    function escapeHtml(value) {
        return String(value == null ? '' : value)
            .replace(/&/g, '&amp;')
            .replace(/</g, '&lt;')
            .replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;')
            .replace(/'/g, '&#039;');
    }

    function parseQuantityValue(value) {
        const qty = Number(String(value == null ? '' : value).trim().replace(',', '.'));
        if (!Number.isFinite(qty) || qty <= 0) {
            return 1;
        }
        return Math.max(1, Math.floor(qty));
    }

    function parseMoneyValue(value) {
        if (value == null || value === '') {
            return 0;
        }

        let text = String(value).trim().replace(/[^\d,.-]/g, '');

        if (!text) {
            return 0;
        }

        if (text.indexOf(',') !== -1) {
            text = text.replace(/\./g, '').replace(',', '.');
        }

        const amount = Number(text);
        return Number.isFinite(amount) ? amount : 0;
    }

    function formatEuro(value) {
        return Number(value || 0).toLocaleString('de-DE', {
            minimumFractionDigits: 2,
            maximumFractionDigits: 2
        }) + ' €';
    }

    function normalizePartKey(value) {
        return String(value == null ? '' : value).trim().toUpperCase();
    }

    function firstValue(values) {
        for (let i = 0; i < values.length; i++) {
            if (values[i] != null && values[i] !== '') {
                return values[i];
            }
        }
        return '';
    }

    function productValue(product, keys) {
        for (let i = 0; i < keys.length; i++) {
            const key = keys[i];
            if (product && product[key] != null && product[key] !== '') {
                return product[key];
            }
        }
        return '';
    }

    function isHeaderPartNumber(value) {
        return /^(teilenummer|artikelnummer|part|part_number|sku|nummer|nr\.?|number)$/i.test(String(value || '').trim());
    }

    function normalizePartEntries(input) {
        const entries = [];

        String(input || '').split(/[\n\r]+/).forEach(function (line) {
            const cleanLine = line.trim();

            if (!cleanLine) {
                return;
            }

            const separated = cleanLine
                .split(/[;\t,]+/)
                .map(function (part) { return part.trim(); })
                .filter(Boolean);

            if (separated.length === 2 && /^\d+(?:[\.,]\d+)?$/.test(separated[1])) {
                entries.push({
                    part_number: separated[0],
                    quantity: parseQuantityValue(separated[1])
                });
                return;
            }

            const whitespaceQty = cleanLine.match(/^(.+?)\s+(\d+(?:[\.,]\d+)?)$/);

            if (whitespaceQty) {
                entries.push({
                    part_number: whitespaceQty[1].trim(),
                    quantity: parseQuantityValue(whitespaceQty[2])
                });
                return;
            }

            separated.forEach(function (part) {
                entries.push({
                    part_number: part,
                    quantity: 1
                });
            });
        });

        return entries.filter(function (entry) {
            return entry.part_number;
        });
    }

    document.addEventListener('DOMContentLoaded', function () {
        const tabs = document.querySelectorAll('.baf-tab');
        const panels = document.querySelectorAll('.baf-tab-panel');

        const statusBox = document.getElementById('bafStatus');
        const resultsBody = document.getElementById('resultsBody');
        const resultsEmpty = document.getElementById('resultsEmpty');
        const resultsTableWrap = document.getElementById('resultsTableWrap');
        const resultsFooter = document.getElementById('resultsFooter');
        const resultsNetTotal = document.getElementById('resultsNetTotal');
        const ambiguousBox = document.getElementById('bafAmbiguous');
        const notFoundBox = document.getElementById('bafNotFound');
        const surchargeInfoBox = document.getElementById('bafSurchargeInfo');
        const resultsDeleteBtn = document.getElementById('resultsDeleteBtn');
        const addAllResultsBtn = document.getElementById('addAllResultsBtn');
        const templateDownloadBtn = document.getElementById('templateDownloadBtn');
        const selectAll = document.getElementById('selectAll');
        const cartInfo = document.getElementById('bafCartInfo');
        const loadingOverlay = document.getElementById('bafLoadingOverlay');
        const loadingText = document.getElementById('bafLoadingText');

        let pendingQuantityByPart = {};

        function resetInitialUiState() {
            if (statusBox) {
                statusBox.textContent = '';
            }

            if (ambiguousBox) {
                ambiguousBox.innerHTML = '';
                ambiguousBox.hidden = true;
            }

            if (notFoundBox) {
                notFoundBox.innerHTML = '';
                notFoundBox.hidden = true;
            }

            if (surchargeInfoBox) {
                surchargeInfoBox.innerHTML = '';
                surchargeInfoBox.hidden = true;
            }

            if (resultsBody) {
                resultsBody.innerHTML = '';
            }

            if (resultsTableWrap) {
                resultsTableWrap.hidden = true;
            }

            if (resultsFooter) {
                resultsFooter.hidden = true;
            }

            if (resultsEmpty) {
                resultsEmpty.hidden = false;
            }

            if (selectAll) {
                selectAll.checked = false;
            }

            if (addAllResultsBtn) {
                addAllResultsBtn.disabled = true;
                addAllResultsBtn.textContent = 'Alle Ergebnisse in den Warenkorb';
            }

            if (resultsDeleteBtn) {
                resultsDeleteBtn.disabled = true;
                resultsDeleteBtn.textContent = 'Komplette Liste löschen';
            }

            if (cartInfo) {
                cartInfo.textContent = 'Ergebnisliste bereit';
            }

            if (loadingOverlay) {
                loadingOverlay.hidden = true;
            }

            if (loadingText) {
                loadingText.textContent = 'Bitte bleiben Sie auf dieser Seite. Die Liste wird verarbeitet.';
            }
        }

        function resetTabsToSingleSearch() {
            document.querySelectorAll('.baf-tab').forEach(function (tab) {
                tab.classList.remove('is-active');

                if (tab.dataset.tab === 'single') {
                    tab.classList.add('is-active');
                }
            });

            document.querySelectorAll('.baf-tab-panel').forEach(function (panel) {
                panel.classList.remove('is-active');

                if (panel.id === 'single') {
                    panel.classList.add('is-active');
                }
            });
        }

        resetInitialUiState();
        resetTabsToSingleSearch();

        tabs.forEach(function (tab) {
            tab.addEventListener('click', function () {
                tabs.forEach(function (item) {
                    item.classList.remove('is-active');
                });

                panels.forEach(function (panel) {
                    panel.classList.remove('is-active');
                });

                tab.classList.add('is-active');
                document.getElementById(tab.dataset.tab).classList.add('is-active');
            });
        });

        document.getElementById('singleSearchBtn').addEventListener('click', function () {
            searchParts(normalizePartEntries(document.getElementById('singlePart').value));
        });

        document.getElementById('singlePart').addEventListener('keydown', function (event) {
            if (event.key === 'Enter') {
                event.preventDefault();
                searchParts(normalizePartEntries(document.getElementById('singlePart').value));
            }
        });

        document.getElementById('multiSearchBtn').addEventListener('click', function () {
            searchParts(normalizePartEntries(document.getElementById('multiParts').value));
        });

        document.getElementById('uploadBtn').addEventListener('click', uploadPartsList);

        selectAll.addEventListener('change', function () {
            document.querySelectorAll('.baf-row-select').forEach(function (cb) {
                if (!cb.disabled) {
                    cb.checked = selectAll.checked;
                }
            });

            updateActionButtons();
        });

        resultsDeleteBtn.addEventListener('click', function () {
            const selectedRows = Array.from(document.querySelectorAll('.baf-row-select:checked'))
                .map(function (cb) {
                    return cb.closest('tr');
                })
                .filter(Boolean);

            if (selectedRows.length) {
                removeRows(selectedRows, selectedRows.length + ' ausgewählte Position(en) gelöscht.');
                return;
            }

            clearAllResults();
        });

        addAllResultsBtn.addEventListener('click', function () {
            const selected = getSelectedItems();

            if (selected.items.length) {
                addItemsToCart(selected.items, selected.rows, true);
                return;
            }

            const all = getAllOrderableItems();

            if (all.items.length) {
                addItemsToCart(all.items, all.rows, true);
            } else {
                setStatus('Es gibt keine bestellbaren Artikel in der Ergebnisliste.');
            }
        });

        if (templateDownloadBtn) {
            templateDownloadBtn.addEventListener('click', function () {
                const csvContent = [
                    ['Teilenummer', 'Anzahl'],
                    ['LR123456', '2'],
                    ['07119963132', '4'],
                    ['LR777777', '1']
                ].map(function (row) {
                    return row.join(';');
                }).join('\n');

                const blob = new Blob([csvContent], {
                    type: 'text/csv;charset=utf-8;'
                });

                const url = window.URL.createObjectURL(blob);
                const link = document.createElement('a');

                link.href = url;
                link.download = 'BAF_Bestellvorlage.csv';
                document.body.appendChild(link);
                link.click();
                document.body.removeChild(link);

                window.URL.revokeObjectURL(url);
                setStatus('Vorlage wurde heruntergeladen.');
            });
        }

        async function searchParts(partEntries, brandChoices) {
            const entries = (partEntries || []).map(function (entry) {
                return {
                    part_number: entry.part_number || entry.part || entry.sku || '',
                    quantity: parseQuantityValue(entry.quantity || entry.qty || entry.requested_quantity || 1)
                };
            }).filter(function (entry) {
                return entry.part_number;
            });

            if (!entries.length) {
                setStatus('Bitte mindestens eine Teilenummer eingeben.');
                return;
            }

            entries.forEach(function (entry) {
                pendingQuantityByPart[normalizePartKey(entry.part_number)] = entry.quantity;
            });

            setStatus('Teilenummern werden geprüft und zur Ergebnisliste hinzugefügt...');

            try {
                let result = await jsonrpc(BAF_API.search, {
                    part_numbers: entries.map(function (entry) {
                        return entry.part_number;
                    }),
                    quantities: pendingQuantityByPart,
                    brand_choices: brandChoices || {}
                });

                result = await autoResolveLeadingZeroFallback(result);
                appendResults(result);
            } catch (error) {
                console.error(error);
                setStatus('Die Suche konnte nicht ausgeführt werden. Bitte erneut versuchen.');
            }
        }

        async function autoResolveLeadingZeroFallback(data) {
            const originalNotFound = data && data.not_found ? data.not_found : [];
            const candidates = [];

            originalNotFound.forEach(function (value) {
                const original = String(value == null ? '' : value).trim();

                if (!original) {
                    return;
                }

                if (!/^\d+$/.test(original)) {
                    return;
                }

                if (original.charAt(0) === '0') {
                    return;
                }

                candidates.push({
                    original: original,
                    prefixed: '0' + original
                });
            });

            if (!candidates.length) {
                return data;
            }

            const quantities = Object.assign({}, pendingQuantityByPart);

            candidates.forEach(function (candidate) {
                const originalKey = normalizePartKey(candidate.original);
                const prefixedKey = normalizePartKey(candidate.prefixed);
                const qty = parseQuantityValue(pendingQuantityByPart[originalKey] || 1);

                pendingQuantityByPart[prefixedKey] = qty;
                quantities[prefixedKey] = qty;
            });

            try {
                const retryResult = await jsonrpc(BAF_API.search, {
                    part_numbers: candidates.map(function (candidate) {
                        return candidate.prefixed;
                    }),
                    quantities: quantities,
                    brand_choices: {},
                    leading_zero_retry: true
                });

                const retryProducts = retryResult && retryResult.products ? retryResult.products : [];
                const retryAmbiguous = retryResult && retryResult.ambiguous ? retryResult.ambiguous : [];
                const foundKeys = new Set();

                retryProducts.forEach(function (product) {
                    [
                        product.part_number,
                        product.default_code,
                        product.sku,
                        product.original_part_number,
                        product.search_part_number
                    ].forEach(function (value) {
                        const key = normalizePartKey(value);

                        if (key) {
                            foundKeys.add(key);
                        }
                    });
                });

                retryAmbiguous.forEach(function (entry) {
                    const key = normalizePartKey(entry.part_number);

                    if (key) {
                        foundKeys.add(key);
                    }
                });

                const fixedOriginalKeys = new Set();

                candidates.forEach(function (candidate) {
                    const prefixedKey = normalizePartKey(candidate.prefixed);

                    if (foundKeys.has(prefixedKey)) {
                        fixedOriginalKeys.add(normalizePartKey(candidate.original));
                    }
                });

                if (!fixedOriginalKeys.size) {
                    return data;
                }

                const merged = Object.assign({}, data);

                merged.products = (data && data.products ? data.products : []).concat(retryProducts);
                merged.ambiguous = (data && data.ambiguous ? data.ambiguous : []).concat(retryAmbiguous);
                merged.not_found = originalNotFound.filter(function (value) {
                    return !fixedOriginalKeys.has(normalizePartKey(value));
                });
                merged.leading_zero_fixed_count = fixedOriginalKeys.size;

                return merged;
            } catch (error) {
                console.warn('Leading zero retry failed', error);
                return data;
            }
        }

        async function uploadPartsList() {
            const file = document.getElementById('partsFile').files[0];

            if (!file) {
                setStatus('Bitte zuerst eine Excel- oder CSV-Datei auswählen.');
                return;
            }

            setStatus('Liste wird geprüft und zur bestehenden Ergebnisliste hinzugefügt...');

            try {
                let uploadQuantityMap = {};

                if (/\.(csv|txt)$/i.test(file.name)) {
                    uploadQuantityMap = await readCsvQuantityMap(file);
                } else if (/\.(xlsx|xls)$/i.test(file.name)) {
                    uploadQuantityMap = await readExcelQuantityMap(file);
                }

                Object.keys(uploadQuantityMap).forEach(function (key) {
                    pendingQuantityByPart[normalizePartKey(key)] = uploadQuantityMap[key];
                });

                const formData = new FormData();

                formData.append('file', file);
                formData.append('quantities', JSON.stringify(uploadQuantityMap));

                const response = await fetch(BAF_API.upload, {
                    method: 'POST',
                    body: formData,
                    credentials: 'same-origin'
                });

                if (!response.ok) {
                    throw new Error('HTTP ' + response.status);
                }

                const rawData = await response.json();
                let data = rawData && rawData.result ? rawData.result : rawData;

                applyQuantitiesToProducts(data, uploadQuantityMap);

                data = await autoResolveLeadingZeroFallback(data);
                appendResults(data);
            } catch (error) {
                console.error(error);
                setStatus('Die Liste konnte nicht verarbeitet werden. Bitte Format prüfen.');
            }
        }

        function readCsvQuantityMap(file) {
            return new Promise(function (resolve, reject) {
                const reader = new FileReader();

                reader.onload = function () {
                    try {
                        const text = String(reader.result || '');
                        const map = {};

                        text.split(/\r?\n/).forEach(function (line) {
                            const cleanLine = line.trim();

                            if (!cleanLine) {
                                return;
                            }

                            const cols = cleanLine.split(/[;\t,]/).map(function (value) {
                                return value.trim();
                            });

                            const partNumber = cols[0];
                            const quantity = cols.length > 1 ? cols[1] : 1;

                            if (!partNumber || isHeaderPartNumber(partNumber)) {
                                return;
                            }

                            map[normalizePartKey(partNumber)] = parseQuantityValue(quantity || 1);
                        });

                        resolve(map);
                    } catch (error) {
                        reject(error);
                    }
                };

                reader.onerror = reject;
                reader.readAsText(file);
            });
        }

        function readExcelQuantityMap(file) {
            return new Promise(function (resolve, reject) {
                if (typeof XLSX === 'undefined') {
                    reject(new Error('Excel-Bibliothek XLSX wurde nicht geladen.'));
                    return;
                }

                const reader = new FileReader();

                reader.onload = function (event) {
                    try {
                        const data = new Uint8Array(event.target.result);
                        const workbook = XLSX.read(data, {type: 'array'});
                        const sheet = workbook.Sheets[workbook.SheetNames[0]];

                        const rows = XLSX.utils.sheet_to_json(sheet, {
                            header: 1,
                            raw: false,
                            defval: ''
                        });

                        const map = {};

                        rows.forEach(function (row) {
                            if (!row || !row.length) {
                                return;
                            }

                            let partNumber = String(row[0] || '').trim();
                            const quantity = row.length > 1 ? row[1] : 1;

                            if (!partNumber || isHeaderPartNumber(partNumber)) {
                                return;
                            }

                            partNumber = partNumber.replace(/\.0$/, '');
                            map[normalizePartKey(partNumber)] = parseQuantityValue(quantity || 1);
                        });

                        resolve(map);
                    } catch (error) {
                        reject(error);
                    }
                };

                reader.onerror = reject;
                reader.readAsArrayBuffer(file);
            });
        }

        function applyQuantitiesToProducts(data, quantityMap) {
            const products = data && data.products ? data.products : [];

            products.forEach(function (product) {
                const keys = [
                    product.part_number,
                    product.default_code,
                    product.sku,
                    product.part,
                    product.search_part_number,
                    product.original_part_number
                ].map(normalizePartKey).filter(Boolean);

                for (let i = 0; i < keys.length; i++) {
                    const key = keys[i];

                    if (quantityMap[key] != null) {
                        product.quantity = quantityMap[key];
                        product.requested_quantity = quantityMap[key];
                        pendingQuantityByPart[key] = quantityMap[key];
                        return;
                    }

                    if (pendingQuantityByPart[key] != null) {
                        product.quantity = pendingQuantityByPart[key];
                        product.requested_quantity = pendingQuantityByPart[key];
                        return;
                    }
                }
            });
        }

        function appendResults(data) {
            const products = data && data.products ? data.products : [];
            const ambiguous = data && data.ambiguous ? data.ambiguous : [];
            const notFound = data && data.not_found ? data.not_found : [];

            products.forEach(function (product) {
                const key = normalizePartKey(product.part_number);
                const existing = findExistingResultRow(key);
                const newRow = buildProductRow(product);

                newRow.classList.add('is-updated');

                if (existing) {
                    resultsBody.replaceChild(newRow, existing);
                } else {
                    resultsBody.appendChild(newRow);
                }
            });

            if (ambiguous.length) {
                renderAmbiguous(ambiguous);
            }

            if (notFound.length) {
                renderNotFound(notFound);
            } else {
                notFoundBox.hidden = true;
                notFoundBox.innerHTML = '';
            }

            refreshResultsVisibility();

            const parts = [];

            if (products.length) {
                parts.push(products.length + ' Artikel zur Ergebnisliste hinzugefügt.');
            }

            if (data && data.leading_zero_fixed_count) {
                parts.push(data.leading_zero_fixed_count + ' Artikel mit führender 0 automatisch erkannt.');
            }

            if (ambiguous.length) {
                parts.push(ambiguous.length + ' SKU(s) mehrdeutig - bitte Marke wählen.');
            }

            if (notFound.length) {
                parts.push(notFound.length + ' nicht gefunden.');
            }

            setStatus(parts.join(' ') || 'Keine Treffer.');
        }

        function findExistingResultRow(key) {
            const rows = Array.from(resultsBody.querySelectorAll('tr'));
            const normalizedKey = normalizePartKey(key);

            for (let i = 0; i < rows.length; i++) {
                if (normalizePartKey(rows[i].dataset.partKey) === normalizedKey) {
                    return rows[i];
                }
            }

            return null;
        }

        function translateProductMod(value) {
            const mod = String(value == null ? '' : value).trim();
            const normalized = mod.toLowerCase();

            if (!mod) {
                return '';
            }

            if (normalized === 'motorcycle') {
                return 'Motorrad';
            }

            if (mod.toUpperCase() === 'SB' || normalized === 'sb (supplier 1 surcharge)') {
                return 'Car';
            }

            return mod;
        }

        function displayBrand(brand) {
            const value = String(brand == null ? '' : brand).trim();

            if (!value) {
                return '';
            }

            return value.toLowerCase() === 'land rover' ? 'LR' : value;
        }

        function getProductMod(product) {
            const rawMod = firstValue([
                productValue(product, ['mod', 'Mod', 'baf_mod', 'pricing_mod', 'x_mod', 'x_studio_mod']),
                product.baf_pricing && product.baf_pricing.mod,
                product.pricing && product.pricing.mod
            ]);

            return translateProductMod(rawMod);
        }

        function getProductType(product) {
            return firstValue([
                productValue(product, ['type', 'Type', 'tpe', 'tpe_code', 'Tpe Code (1-9)', 'tpe_code_1_9', 'baf_tpe_code', 'pricing_tpe_code', 'x_tpe_code', 'x_studio_tpe_code']),
                product.baf_pricing && (product.baf_pricing.tpe_code || product.baf_pricing.type),
                product.pricing && (product.pricing.tpe_code || product.pricing.type)
            ]);
        }

        function getProductSurchargeAmount(product) {
            return parseMoneyValue(firstValue([
                productValue(product, ['Surcharge', 'surcharge', 'surcharge_amount', 'surchargeAmount']),
                product.baf_pricing && (product.baf_pricing.Surcharge || product.baf_pricing.surcharge || product.baf_pricing.surcharge_amount),
                product.pricing && (product.pricing.Surcharge || product.pricing.surcharge || product.pricing.surcharge_amount)
            ]));
        }

        function getProductMOQ(product) {
            const raw = firstValue([
                productValue(product, ['Unit of Sales', 'unit_of_sales', 'unitOfSales', 'UnitOfSales', 'moq', 'MOQ']),
                product.baf_pricing && (
                    product.baf_pricing['Unit of Sales'] ||
                    product.baf_pricing.unit_of_sales ||
                    product.baf_pricing.unitOfSales ||
                    product.baf_pricing.UnitOfSales ||
                    product.baf_pricing.moq ||
                    product.baf_pricing.MOQ
                ),
                product.pricing && (
                    product.pricing['Unit of Sales'] ||
                    product.pricing.unit_of_sales ||
                    product.pricing.unitOfSales ||
                    product.pricing.UnitOfSales ||
                    product.pricing.moq ||
                    product.pricing.MOQ
                )
            ]);

            return parseQuantityValue(raw || 1);
        }

        function getProductQuantity(product) {
            const candidates = [
                product.quantity,
                product.qty,
                product.requested_quantity,
                product.requested_qty,
                product.order_qty,
                product.product_uom_qty
            ];

            for (let i = 0; i < candidates.length; i++) {
                if (candidates[i] != null && candidates[i] !== '') {
                    return parseQuantityValue(candidates[i]);
                }
            }

            const keys = [
                product.part_number,
                product.default_code,
                product.sku,
                product.original_part_number,
                product.search_part_number
            ].map(normalizePartKey).filter(Boolean);

            for (let i = 0; i < keys.length; i++) {
                if (pendingQuantityByPart[keys[i]] != null) {
                    return parseQuantityValue(pendingQuantityByPart[keys[i]]);
                }
            }

            return 1;
        }

        function getOdooAvailabilityText(product) {
            return firstValue([
                productValue(product, ['availability', 'Availability', 'availability_status', 'availability_label', 'status', 'sale_status', 'product_status']),
                product.baf_pricing && (product.baf_pricing.availability || product.baf_pricing.availability_status || product.baf_pricing.status),
                product.pricing && (product.pricing.availability || product.pricing.availability_status || product.pricing.status)
            ]);
        }

        function getOdooAvailabilityType(product) {
            return firstValue([
                productValue(product, ['availability_type', 'Availability Type', 'availability_code', 'status_type', 'sale_status_type']),
                product.baf_pricing && (product.baf_pricing.availability_type || product.baf_pricing.status_type),
                product.pricing && (product.pricing.availability_type || product.pricing.status_type)
            ]);
        }

        function isNLAProduct(product) {
            if (product.is_nla === true) {
                return true;
            }

            const availabilityText = String(getOdooAvailabilityText(product) || '').trim().toLowerCase();
            const availabilityType = String(getOdooAvailabilityType(product) || '').trim().toLowerCase();

            return (
                availabilityType === 'nla' ||
                availabilityType === 'discontinued' ||
                availabilityText === 'nla' ||
                availabilityText === 'no longer available' ||
                availabilityText === 'nicht mehr lieferbar' ||
                availabilityText === 'nicht lieferbar' ||
                availabilityText === 'ersatzlos entfallen' ||
                availabilityText === 'discontinued'
            );
        }

        function isExplicitlyBlocked(product) {
            if (isNLAProduct(product)) {
                return true;
            }

            if (product.orderable === false) {
                return true;
            }

            const raw = firstValue([
                productValue(product, ['can_order', 'canOrder', 'sale_ok', 'is_orderable', 'orderable']),
                product.baf_pricing && (product.baf_pricing.can_order || product.baf_pricing.sale_ok || product.baf_pricing.orderable),
                product.pricing && (product.pricing.can_order || product.pricing.sale_ok || product.pricing.orderable)
            ]);

            if (raw === false) {
                return true;
            }

            const text = String(raw == null ? '' : raw).trim().toLowerCase();

            return (
                text === 'false' ||
                text === '0' ||
                text === 'no' ||
                text === 'nein'
            );
        }

        function getReplacementPartNumber(product) {
            return firstValue([
                productValue(product, [
                    'replaced_by_part_number',
                    'replacement_part_number',
                    'replaced_by_sku',
                    'replacement_sku',
                    'successor_part_number',
                    'successor_sku',
                    'Replaced by',
                    'replacement'
                ]),
                product.replaced_by && (
                    product.replaced_by.part_number ||
                    product.replaced_by.default_code ||
                    product.replaced_by.name
                ),
                product.replacement && (
                    product.replacement.part_number ||
                    product.replacement.default_code ||
                    product.replacement.name
                ),
                product.successor && (
                    product.successor.part_number ||
                    product.successor.default_code ||
                    product.successor.name
                )
            ]);
        }

        function getReplacementProductId(product) {
            const value = firstValue([
                productValue(product, [
                    'replaced_by_product_id',
                    'replacement_product_id',
                    'replaced_by_id',
                    'replacement_id',
                    'successor_product_id'
                ]),
                product.replaced_by && product.replaced_by.id,
                product.replacement && product.replacement.id,
                product.successor && product.successor.id
            ]);

            return value ? Number(value) : 0;
        }

        function getReplacementUrl(product) {
            return firstValue([
                productValue(product, ['replacement_url', 'replaced_by_url', 'successor_url']),
                product.replaced_by && product.replaced_by.url,
                product.replacement && product.replacement.url,
                product.successor && product.successor.url
            ]);
        }

        function getReplacementProductIdFromUrl(product) {
            const url = String(getReplacementUrl(product) || '').trim();

            if (!url) {
                return 0;
            }

            const match = url.match(/-(\d+)(?:[/?#]|$)/) || url.match(/\/(\d+)(?:[/?#]|$)/);

            if (!match) {
                return 0;
            }

            const value = Number(match[1]);

            return Number.isFinite(value) && value > 0 ? value : 0;
        }

        function getEmbeddedReplacementProduct(product) {
            const replacement = product.replaced_by || product.replacement || product.successor || null;

            if (!replacement || typeof replacement !== 'object') {
                return null;
            }

            const replacementId = replacement.id || getReplacementProductId(product);
            const replacementPartNumber = replacement.part_number || replacement.default_code || getReplacementPartNumber(product);

            if (!replacementId && !replacementPartNumber) {
                return null;
            }

            const merged = Object.assign({}, replacement);

            merged.id = replacementId || replacement.id;
            merged.part_number = replacementPartNumber || replacement.part_number || replacement.default_code;
            merged.default_code = replacementPartNumber || replacement.default_code;
            merged.quantity = product.quantity || product.requested_quantity || product.qty || 1;
            merged.requested_quantity = product.requested_quantity || product.quantity || product.qty || 1;

            if (!merged.name) {
                merged.name = replacement.name || product.replacement_name || product.replaced_by_name || '';
            }

            return merged;
        }

        function hasReplacement(product) {
            return Boolean(
                getReplacementPartNumber(product) ||
                getReplacementProductId(product) ||
                getReplacementProductIdFromUrl(product) ||
                getReplacementUrl(product) ||
                getEmbeddedReplacementProduct(product)
            );
        }

        function getNetUnitPrice(product) {
            const directNet = firstValue([
                productValue(product, ['net_price', 'netPrice', 'price_net', 'b2b_net_price', 'base_price', 'Base Price']),
                product.pricing && (
                    product.pricing.net_price ||
                    product.pricing.netPrice ||
                    product.pricing.price_net ||
                    product.pricing.base_price
                ),
                product.baf_pricing && (
                    product.baf_pricing.net_price ||
                    product.baf_pricing.netPrice ||
                    product.baf_pricing.price_net ||
                    product.baf_pricing.base_price
                )
            ]);

            const directValue = parseMoneyValue(directNet);

            if (directValue > 0) {
                return directValue;
            }

            return parseMoneyValue(product.price) + getProductSurchargeAmount(product);
        }

        function getDisplayPriceWithSurcharge(product) {
            const basePrice = parseMoneyValue(product.price);
            const surcharge = getProductSurchargeAmount(product);

            if (!surcharge) {
                return {
                    total: product.price || 'Preis nach Login'
                };
            }

            if (!basePrice) {
                return {
                    total: product.price || 'Preis nach Login'
                };
            }

            return {
                total: formatEuro(basePrice + surcharge)
            };
        }

        function shortenDeliveryText(value) {
            let text = String(value || '').trim();

            if (!text || text === '—' || text === '--') {
                return '';
            }

            text = text
                .replace(/voraussichtliche Lieferzeit/ig, 'Lieferzeit')
                .replace(/Lieferzeit ca\./ig, 'ca.')
                .replace(/Werktage/ig, 'WT')
                .replace(/Arbeitstage/ig, 'AT')
                .replace(/Tage/ig, 'T.')
                .replace(/\s+/g, ' ')
                .trim();

            if (text.length > 20) {
                text = text.slice(0, 19).trim() + '…';
            }

            return text;
        }

        function getDeliveryHtml(product, isReplaced, isNla, isBlocked) {
            const deliveryRaw = firstValue([
                product.delivery_time,
                product.deliveryTime,
                product.lead_time,
                product.delivery,
                product.baf_pricing && (product.baf_pricing.delivery_time || product.baf_pricing.lead_time),
                product.pricing && (product.pricing.delivery_time || product.pricing.lead_time)
            ]);

            const deliveryTime = shortenDeliveryText(deliveryRaw);
            const availabilityText = getOdooAvailabilityText(product);
            const availabilityTypeRaw = String(getOdooAvailabilityType(product) || '').trim().toLowerCase();
            const replacementPartNumber = getReplacementPartNumber(product);
            const replacementUrl = getReplacementUrl(product);
            const embeddedReplacement = getEmbeddedReplacementProduct(product);

            let statusText = '';
            let statusType = '';

            if (isNla) {
                statusText = 'NLA';
                statusType = 'nla';
            } else if (isReplaced) {
                if (replacementPartNumber) {
                    statusText = 'Ersetzung: ' + replacementPartNumber;
                } else if (replacementUrl || embeddedReplacement) {
                    statusText = 'Ersetzung vorhanden';
                } else {
                    statusText = 'Ersetzung vorhanden';
                }

                statusType = 'replacement';
            } else if (isBlocked) {
                statusText = availabilityText || 'Nicht bestellbar';
                statusType = 'no';
            } else if (availabilityText) {
                statusText = availabilityText;
                statusType = availabilityTypeRaw || 'ok';
            }

            let html = '<span class="baf-info-cell">';

            if (deliveryTime) {
                html += '<span class="baf-delivery-main" title="' + escapeHtml(deliveryRaw) + '">' + escapeHtml(deliveryTime) + '</span>';
            }

            if (statusText) {
                html += '<span class="baf-delivery-status ' + escapeHtml(statusType) + '" title="' + escapeHtml(statusText) + '">' + escapeHtml(statusText) + '</span>';
            }

            html += '</span>';

            return html;
        }

        function buildProductRow(product) {
            const row = document.createElement('tr');

            const moq = getProductMOQ(product);
            const requestedQty = getProductQuantity(product);
            const quantity = Math.max(requestedQty, moq);

            const replacementProductId = getReplacementProductId(product);
            const replacementUrl = getReplacementUrl(product);
            const replacementPartNumber = getReplacementPartNumber(product);
            const replacementProductIdFromUrl = getReplacementProductIdFromUrl(product);
            const embeddedReplacement = getEmbeddedReplacementProduct(product);

            const isReplaced = hasReplacement(product);
            const isNla = isNLAProduct(product);
            const isBlocked = isExplicitlyBlocked(product);

            const orderProductId = Number(product.id || 0);
            const canOrder = !isNla && !isBlocked && Boolean(orderProductId);

            const surchargeAmount = getProductSurchargeAmount(product);
            const priceInfo = getDisplayPriceWithSurcharge(product);
            const deliveryHtml = getDeliveryHtml(product, isReplaced, isNla, isBlocked);
            const netUnitPrice = getNetUnitPrice(product);

            row.dataset.productId = product.id || '';
            row.dataset.orderProductId = orderProductId || '';
            row.dataset.partKey = normalizePartKey(product.part_number);
            row.dataset.surchargeAmount = surchargeAmount || 0;
            row.dataset.hasSurcharge = surchargeAmount > 0 ? '1' : '0';
            row.dataset.surchargeLabel = surchargeAmount > 0 ? 'Surcharge: ' + formatEuro(surchargeAmount) : '';
            row.dataset.moq = moq;
            row.dataset.netUnitPrice = canOrder ? (netUnitPrice || 0) : 0;
            row.dataset.note = '';
            row.dataset.canOrder = canOrder ? '1' : '0';

            if (!canOrder) {
                row.classList.add('baf-row-blocked');
            }

            const surchargeHtml = surchargeAmount > 0
                ? '<span class="baf-surcharge-line">Surcharge: ' + escapeHtml(formatEuro(surchargeAmount)) + '</span>'
                : '';

            let actionHtml = '';

            if (canOrder) {
                actionHtml = '<button class="baf-add-btn" type="button">Hinzufügen</button>';
            } else if (isNla) {
                actionHtml = '<span class="baf-blocked-label">NLA</span>';
            } else if (replacementUrl || replacementPartNumber || replacementProductId || replacementProductIdFromUrl || embeddedReplacement) {
                actionHtml = '<button class="baf-add-btn baf-replacement-btn" type="button">Nachfolger</button>';
            } else {
                actionHtml = '<span class="baf-blocked-label">Nicht bestellbar</span>';
            }

            row.innerHTML =
                '<td><input class="baf-row-select" type="checkbox" ' + (!canOrder ? 'disabled="disabled"' : '') + '/></td>' +
                '<td><span class="baf-position-number"></span></td>' +
                '<td>' + escapeHtml(displayBrand(product.brand || product.manufacturer || product.make)) + '</td>' +
                '<td>' + escapeHtml(getProductMod(product)) + '</td>' +
                '<td>' + escapeHtml(getProductType(product)) + '</td>' +
                '<td><span class="baf-part-number">' + escapeHtml(product.part_number || '') + '</span></td>' +
                '<td><span class="baf-product-name" title="' + escapeHtml(product.name || '') + '">' + escapeHtml(product.name || '') + '</span></td>' +
                '<td>' + deliveryHtml + '</td>' +
                '<td><span class="baf-moq-badge">' + escapeHtml(moq) + '</span></td>' +
                '<td class="baf-price-cell"><strong class="baf-price-main">' + escapeHtml(canOrder ? priceInfo.total : '') + '</strong>' + (canOrder ? surchargeHtml : '') + '</td>' +
                '<td><input class="baf-qty" type="number" min="' + escapeHtml(moq) + '" step="' + escapeHtml(moq) + '" value="' + escapeHtml(quantity) + '" ' + (!canOrder ? 'disabled="disabled"' : '') + '/></td>' +
                '<td>' +
                    '<div class="baf-note-wrap">' +
                        '<button class="baf-note-btn" type="button" title="Notiz hinzufügen">&#x270E;</button>' +
                        '<div class="baf-note-popover" hidden="hidden">' +
                            '<textarea class="baf-note-text" placeholder="Notiz zu dieser Position eingeben..."></textarea>' +
                            '<div class="baf-note-actions">' +
                                '<button class="baf-note-close" type="button">Schließen</button>' +
                                '<button class="baf-note-save" type="button">Speichern</button>' +
                            '</div>' +
                        '</div>' +
                    '</div>' +
                '</td>' +
                '<td><div class="baf-row-actions">' +
                    actionHtml +
                    '<button class="baf-remove-btn" type="button">Löschen</button>' +
                '</div></td>';

            const selectBox = row.querySelector('.baf-row-select');

            if (selectBox) {
                selectBox.addEventListener('change', updateActionButtons);
            }

            const qtyInput = row.querySelector('.baf-qty');

            if (qtyInput) {
                qtyInput.addEventListener('change', function () {
                    let qty = parseQuantityValue(qtyInput.value);

                    if (qty < moq) {
                        qty = moq;
                    }

                    qtyInput.value = qty;
                    updateResultsTotal();
                });
            }

            const replacementButton = row.querySelector('.baf-replacement-btn');

            if (replacementButton) {
                replacementButton.addEventListener('click', function () {
                    addReplacementToResults(row, product);
                });
            }

            const addButton = row.querySelector('button.baf-add-btn:not(.baf-replacement-btn)');

            if (addButton) {
                addButton.addEventListener('click', function () {
                    const item = buildCartItemFromRow(row);

                    if (!item.product_id) {
                        setStatus('Diese Position hat keine gültige Produkt-ID.');
                        return;
                    }

                    addItemsToCart([item], [row], false);
                });
            }

            row.querySelector('.baf-remove-btn').addEventListener('click', function () {
                removeRows([row], 'Position aus der Ergebnisliste gelöscht.');
            });

            const noteBtn = row.querySelector('.baf-note-btn');
            const notePopover = row.querySelector('.baf-note-popover');
            const noteText = row.querySelector('.baf-note-text');

            noteBtn.addEventListener('click', function () {
                closeAllNotePopovers(row);
                notePopover.hidden = !notePopover.hidden;

                if (!notePopover.hidden) {
                    noteText.focus();
                }
            });

            row.querySelector('.baf-note-save').addEventListener('click', function () {
                row.dataset.note = noteText.value.trim();
                notePopover.hidden = true;
                applyRowNoteState(row);
            });

            row.querySelector('.baf-note-close').addEventListener('click', function () {
                row.dataset.note = noteText.value.trim();
                notePopover.hidden = true;
                applyRowNoteState(row);
            });

            noteText.addEventListener('input', function () {
                row.dataset.note = noteText.value.trim();
                applyRowNoteState(row);
            });

            applyRowNoteState(row);

            return row;
        }

        async function addReplacementToResults(row, product) {
            const embeddedReplacement = getEmbeddedReplacementProduct(product);
            const replacementPartNumber = getReplacementPartNumber(product);
            const replacementProductId = getReplacementProductId(product);
            const replacementProductIdFromUrl = getReplacementProductIdFromUrl(product);
            const replacementUrl = getReplacementUrl(product);
            const qtyInput = row.querySelector('.baf-qty');
            const currentQty = qtyInput ? parseQuantityValue(qtyInput.value || 1) : parseQuantityValue(row.dataset.moq || 1);

            function insertReplacementProduct(replacementProduct) {
                replacementProduct.quantity = currentQty;
                replacementProduct.requested_quantity = currentQty;

                const newRow = buildProductRow(replacementProduct);
                newRow.classList.add('is-updated');

                row.insertAdjacentElement('afterend', newRow);

                updatePositionNumbers();
                updateResultsTotal();
                updateActionButtons();

                setStatus('Nachfolger wurde in die Ergebnisliste eingefügt.');
            }

            if (embeddedReplacement) {
                insertReplacementProduct(embeddedReplacement);
                return;
            }

            if (!replacementPartNumber && !replacementProductId && !replacementProductIdFromUrl && !replacementUrl) {
                setStatus('Für diese Position wurde kein eindeutiger Nachfolger von Odoo übergeben.');
                return;
            }

            setStatus('Nachfolger wird geladen...');

            try {
                const effectiveReplacementProductId = replacementProductId || replacementProductIdFromUrl;

                const params = {
                    part_numbers: replacementPartNumber ? [replacementPartNumber] : [],
                    product_ids: effectiveReplacementProductId ? [effectiveReplacementProductId] : [],
                    replacement_url: replacementUrl || '',
                    quantities: {},
                    replacement_of: product.part_number || ''
                };

                if (replacementPartNumber) {
                    params.quantities[normalizePartKey(replacementPartNumber)] = currentQty;
                    pendingQuantityByPart[normalizePartKey(replacementPartNumber)] = currentQty;
                }

                const result = await jsonrpc(BAF_API.search, params);
                const products = result && result.products ? result.products : [];

                if (!products.length) {
                    setStatus('Nachfolger konnte nicht geladen werden. Bitte Backend-Verknüpfung prüfen.');
                    return;
                }

                insertReplacementProduct(products[0]);
            } catch (error) {
                console.error(error);
                setStatus('Nachfolger konnte nicht geladen werden. Bitte Backend-Verknüpfung prüfen.');
            }
        }

        function renderAmbiguous(ambiguous) {
            if (!ambiguous.length) {
                ambiguousBox.hidden = true;
                ambiguousBox.innerHTML = '';
                return;
            }

            let rows = '';
            const allBrands = new Map();

            ambiguous.forEach(function (entry) {
                entry.matches.forEach(function (m) {
                    if (m.brand_id && !allBrands.has(m.brand_id)) {
                        allBrands.set(m.brand_id, displayBrand(m.brand));
                    }
                });

                const opts = entry.matches.map(function (m) {
                    return '<option value="' + escapeHtml(m.brand_id) + '">' +
                        escapeHtml(displayBrand(m.brand)) + ' - ' + escapeHtml(m.name) +
                        '</option>';
                }).join('');

                const skuKey = normalizePartKey(entry.part_number);

                rows +=
                    '<tr class="baf-ambiguous-row" data-sku="' + escapeHtml(entry.part_number) + '" data-sku-key="' + escapeHtml(skuKey) + '">' +
                        '<td><input type="checkbox" class="baf-amb-select"/></td>' +
                        '<td><span class="baf-part-number">' + escapeHtml(entry.part_number) + '</span></td>' +
                        '<td><select class="baf-brand-pick"><option value="">Marke wählen...</option>' + opts + '</select></td>' +
                    '</tr>';
            });

            let bulkOpts = '<option value="">Marke wählen...</option>';

            allBrands.forEach(function (name, id) {
                bulkOpts += '<option value="' + escapeHtml(id) + '">' + escapeHtml(name) + '</option>';
            });

            ambiguousBox.innerHTML =
                '<h3>Mehrdeutige Teilenummern</h3>' +
                '<p>Diese SKUs existieren bei mehreren Marken. Wählen Sie die Marke je SKU und übernehmen Sie die Auswahl.</p>' +
                '<div class="baf-ambiguous-toolbar">' +
                    '<label><input type="checkbox" id="ambSelectAll"/> Alle auswählen</label>' +
                    '<div class="baf-bulk-brand">' +
                        '<span>Marke für ausgewählte:</span>' +
                        '<select id="ambBulkBrand">' + bulkOpts + '</select>' +
                        '<button type="button" class="baf-secondary" id="ambBulkApplyBtn" disabled="disabled">Anwenden</button>' +
                    '</div>' +
                    '<button type="button" id="ambResolveBtn" disabled="disabled">Ausgewählte übernehmen</button>' +
                '</div>' +
                '<table class="baf-table">' +
                    '<thead><tr><th style="width:36px"></th><th>Teilenummer</th><th>Marke</th></tr></thead>' +
                    '<tbody>' + rows + '</tbody>' +
                '</table>';

            ambiguousBox.hidden = false;

            const selAll = ambiguousBox.querySelector('#ambSelectAll');
            const bulkBrandSel = ambiguousBox.querySelector('#ambBulkBrand');
            const bulkApplyBtn = ambiguousBox.querySelector('#ambBulkApplyBtn');
            const resolveBtn = ambiguousBox.querySelector('#ambResolveBtn');

            function refreshBulkApply() {
                const anyChecked = ambiguousBox.querySelectorAll('.baf-amb-select:checked').length > 0;
                bulkApplyBtn.disabled = !(anyChecked && bulkBrandSel.value);
            }

            bulkBrandSel.addEventListener('change', refreshBulkApply);

            bulkApplyBtn.addEventListener('click', function () {
                const brandId = bulkBrandSel.value;

                if (!brandId) {
                    return;
                }

                ambiguousBox.querySelectorAll('tr.baf-ambiguous-row').forEach(function (row) {
                    const cb = row.querySelector('.baf-amb-select');

                    if (!cb.checked) {
                        return;
                    }

                    const sel = row.querySelector('.baf-brand-pick');
                    const opt = sel.querySelector('option[value="' + brandId + '"]');

                    if (opt) {
                        sel.value = brandId;
                    }
                });

                updateAmbiguousToolbar();
                refreshBulkApply();
            });

            selAll.addEventListener('change', function () {
                ambiguousBox.querySelectorAll('.baf-amb-select').forEach(function (cb) {
                    cb.checked = selAll.checked;
                });

                updateAmbiguousToolbar();
                refreshBulkApply();
            });

            ambiguousBox.querySelectorAll('.baf-amb-select').forEach(function (cb) {
                cb.addEventListener('change', function () {
                    updateAmbiguousToolbar();
                    refreshBulkApply();
                });
            });

            ambiguousBox.querySelectorAll('.baf-brand-pick').forEach(function (sel) {
                sel.addEventListener('change', function () {
                    const row = sel.closest('tr.baf-ambiguous-row');
                    const cb = row.querySelector('.baf-amb-select');

                    if (sel.value && !cb.checked) {
                        cb.checked = true;
                    }

                    updateAmbiguousToolbar();
                    refreshBulkApply();
                });
            });

            resolveBtn.addEventListener('click', function () {
                const choices = {};

                ambiguousBox.querySelectorAll('tr.baf-ambiguous-row').forEach(function (row) {
                    const cb = row.querySelector('.baf-amb-select');
                    const brandVal = row.querySelector('.baf-brand-pick').value;

                    if (cb.checked && brandVal) {
                        choices[row.dataset.sku] = Number(brandVal);
                    }
                });

                resolveAmbiguous(choices);
            });

            updateAmbiguousToolbar();
        }

        function updateAmbiguousToolbar() {
            const rows = ambiguousBox.querySelectorAll('tr.baf-ambiguous-row');

            if (!rows.length) {
                return;
            }

            let ready = 0;

            rows.forEach(function (row) {
                const cb = row.querySelector('.baf-amb-select');
                const sel = row.querySelector('.baf-brand-pick');

                if (cb.checked && sel.value) {
                    ready++;
                }
            });

            const btn = ambiguousBox.querySelector('#ambResolveBtn');
            const selAll = ambiguousBox.querySelector('#ambSelectAll');

            if (btn) {
                btn.disabled = ready === 0;
                btn.textContent = ready ? ready + ' ausgewählte übernehmen' : 'Ausgewählte übernehmen';
            }

            if (selAll) {
                const checked = ambiguousBox.querySelectorAll('.baf-amb-select:checked').length;
                selAll.checked = checked > 0 && checked === rows.length;
            }
        }

        async function resolveAmbiguous(choices) {
            const skus = Object.keys(choices);

            if (!skus.length) {
                setStatus('Bitte mindestens eine Marke auswählen.');
                return;
            }

            setStatus('Auswahl wird übernommen...');

            try {
                const result = await jsonrpc(BAF_API.search, {
                    part_numbers: skus,
                    quantities: pendingQuantityByPart,
                    brand_choices: choices
                });

                mergeResolvedResults(result, skus);
            } catch (error) {
                console.error(error);
                setStatus('Die Auswahl konnte nicht übernommen werden.');
            }
        }

        function mergeResolvedResults(data, resolvedSkus) {
            const products = data && data.products ? data.products : [];
            const notFound = data && data.not_found ? data.not_found : [];

            products.forEach(function (product) {
                const key = normalizePartKey(product.part_number);
                const existing = findExistingResultRow(key);
                const newRow = buildProductRow(product);

                newRow.classList.add('is-updated');

                if (existing) {
                    resultsBody.replaceChild(newRow, existing);
                } else {
                    resultsBody.appendChild(newRow);
                }
            });

            const resolvedSkuKeys = new Set(
                (resolvedSkus || []).map(function (sku) {
                    return normalizePartKey(sku);
                })
            );

            ambiguousBox.querySelectorAll('tr.baf-ambiguous-row').forEach(function (row) {
                const rowKey = normalizePartKey(row.dataset.skuKey || row.dataset.sku);

                if (resolvedSkuKeys.has(rowKey)) {
                    row.remove();
                }
            });

            const remaining = ambiguousBox.querySelectorAll('tr.baf-ambiguous-row').length;

            if (!remaining) {
                ambiguousBox.hidden = true;
                ambiguousBox.innerHTML = '';
            } else {
                updateAmbiguousToolbar();
            }

            if (notFound.length) {
                renderNotFound(notFound);
            }

            refreshResultsVisibility();

            const msgParts = [];

            if (products.length) {
                msgParts.push(products.length + ' Artikel übernommen.');
            }

            if (notFound.length) {
                msgParts.push(notFound.length + ' nicht gefunden.');
            }

            if (remaining) {
                msgParts.push(remaining + ' weiterhin offen.');
            }

            if (!remaining && resolvedSkuKeys.size) {
                msgParts.push('Alle mehrdeutigen Positionen wurden übernommen.');
            }

            setStatus(msgParts.join(' ') || 'Auswahl übernommen.');
        }

        function renderNotFound(notFound) {
            if (!notFound.length) {
                notFoundBox.hidden = true;
                notFoundBox.innerHTML = '';
                return;
            }

            notFoundBox.innerHTML =
                '<h3>Nicht gefunden</h3><p>' +
                notFound.map(escapeHtml).join(', ') +
                '</p>';

            notFoundBox.hidden = false;
        }

        function updatePositionNumbers() {
            Array.from(resultsBody.querySelectorAll('tr')).forEach(function (row, index) {
                const pos = row.querySelector('.baf-position-number');

                if (pos) {
                    pos.textContent = String(index + 1);
                }
            });
        }

        function updateResultsTotal() {
            let total = 0;

            Array.from(resultsBody.querySelectorAll('tr')).forEach(function (row) {
                if (row.dataset.canOrder !== '1') {
                    return;
                }

                const unitPrice = parseMoneyValue(row.dataset.netUnitPrice || 0);
                const qtyInput = row.querySelector('.baf-qty');
                const qty = qtyInput ? parseQuantityValue(qtyInput.value || 1) : 0;

                total += unitPrice * qty;
            });

            resultsNetTotal.textContent = formatEuro(total);
            resultsFooter.hidden = resultsBody.querySelectorAll('tr').length === 0;
        }

        function updateSurchargeInfoFromRows() {
            let surchargeCount = 0;

            Array.from(resultsBody.querySelectorAll('tr')).forEach(function (row) {
                if (parseMoneyValue(row.dataset.surchargeAmount || 0) > 0) {
                    surchargeCount++;
                }
            });

            if (!surchargeCount) {
                surchargeInfoBox.hidden = true;
                surchargeInfoBox.innerHTML = '';
                return;
            }

            surchargeInfoBox.hidden = false;
            surchargeInfoBox.innerHTML =
                '<span><strong>Hinweis:</strong> ' +
                surchargeCount +
                ' Artikel enthalten Surcharge. Der angezeigte Preis ist inklusive Surcharge.</span>';
        }

        function refreshResultsVisibility() {
            const hasRows = resultsBody.querySelectorAll('tr').length > 0;

            resultsTableWrap.hidden = !hasRows;

            if (!hasRows) {
                selectAll.checked = false;
                resultsEmpty.hidden = !(ambiguousBox.hidden && notFoundBox.hidden);
                surchargeInfoBox.hidden = true;
                surchargeInfoBox.innerHTML = '';
            } else {
                resultsEmpty.hidden = true;
            }

            updatePositionNumbers();
            updateResultsTotal();
            updateSurchargeInfoFromRows();
            updateActionButtons();
        }

        function buildCartItemFromRow(row) {
            const moq = parseQuantityValue(row.dataset.moq || 1);
            const qtyInput = row.querySelector('.baf-qty');
            let qty = parseQuantityValue(qtyInput ? qtyInput.value || 1 : 1);

            if (qty < moq) {
                qty = moq;

                if (qtyInput) {
                    qtyInput.value = qty;
                }
            }

            return {
                product_id: Number(row.dataset.orderProductId || row.dataset.productId),
                quantity: qty,
                add_qty: qty,
                set_qty: qty,
                moq: moq,
                unit_of_sales: moq,
                surcharge_amount: parseMoneyValue(row.dataset.surchargeAmount || 0),
                has_surcharge: row.dataset.hasSurcharge === '1',
                surcharge_label: row.dataset.hasSurcharge === '1' ? row.dataset.surchargeLabel : '',
                note: row.dataset.note || '',
                customer_note: row.dataset.note || '',
                line_note: row.dataset.note || '',
                internal_note: row.dataset.note || '',
                description: row.dataset.note || '',
                sale_line_note: row.dataset.note || ''
            };
        }

        function getSelectedItems() {
            const rows = Array.from(document.querySelectorAll('#resultsBody tr')).filter(function (row) {
                const cb = row.querySelector('.baf-row-select');
                return cb && cb.checked && !cb.disabled && row.dataset.canOrder === '1';
            });

            return {
                rows: rows,
                items: rows.map(buildCartItemFromRow).filter(function (item) {
                    return item.product_id;
                })
            };
        }

        function getAllOrderableItems() {
            const rows = Array.from(document.querySelectorAll('#resultsBody tr')).filter(function (row) {
                return row.dataset.canOrder === '1';
            });

            return {
                rows: rows,
                items: rows.map(buildCartItemFromRow).filter(function (item) {
                    return item.product_id;
                })
            };
        }

        async function addItemsToCart(items, rowsToRemove, isBulk) {
            if (!items.length) {
                setStatus('Es gibt keine bestellbaren Artikel zum Hinzufügen.');
                return;
            }

            setStatus(items.length + ' Position(en) werden in den Warenkorb gelegt...');

            if (isBulk || items.length > 3) {
                setLoading(true, items.length + ' Position(en) werden verarbeitet. Bitte bleiben Sie auf dieser Seite.');
            }

            try {
                const result = await jsonrpc(BAF_API.addToCart, {
                    items: items
                });

                if (!result || !result.success) {
                    throw new Error('Warenkorb fehlgeschlagen');
                }

                if (result.cart_quantity != null) {
                    cartInfo.textContent = result.cart_quantity + ' Artikel im Warenkorb';
                }

                if (rowsToRemove && rowsToRemove.length) {
                    removeRows(rowsToRemove, items.length + ' Position(en) wurden dem Warenkorb hinzugefügt und aus der Ergebnisliste entfernt.');
                } else {
                    setStatus(items.length + ' Position(en) wurden dem Warenkorb hinzugefügt.');
                }
            } catch (error) {
                console.error(error);
                setStatus('Artikel konnten nicht hinzugefügt werden. Bitte erneut versuchen.');
            } finally {
                setLoading(false);
            }
        }

        function removeRows(rows, message) {
            rows.forEach(function (row) {
                if (row && row.parentNode) {
                    row.parentNode.removeChild(row);
                }
            });

            refreshResultsVisibility();
            setStatus(message || 'Position(en) aus der Ergebnisliste gelöscht.');
        }

        function clearAllResults() {
            resultsBody.innerHTML = '';
            ambiguousBox.innerHTML = '';
            ambiguousBox.hidden = true;
            notFoundBox.innerHTML = '';
            notFoundBox.hidden = true;
            surchargeInfoBox.innerHTML = '';
            surchargeInfoBox.hidden = true;
            selectAll.checked = false;
            pendingQuantityByPart = {};

            refreshResultsVisibility();
            resultsEmpty.hidden = false;
            setStatus('Die Ergebnisliste wurde vollständig gelöscht.');
        }

        function updateActionButtons() {
            const selectedCount = document.querySelectorAll('.baf-row-select:checked:not(:disabled)').length;
            const rowCount = resultsBody.querySelectorAll('tr').length;
            const orderableCount = resultsBody.querySelectorAll('tr[data-can-order="1"]').length;

            resultsDeleteBtn.disabled = rowCount === 0 && ambiguousBox.hidden && notFoundBox.hidden;

            if (selectedCount > 0) {
                resultsDeleteBtn.textContent = 'Auswahl löschen';
            } else {
                resultsDeleteBtn.textContent = 'Komplette Liste löschen';
            }

            addAllResultsBtn.disabled = orderableCount === 0;

            if (selectedCount > 0) {
                addAllResultsBtn.textContent = selectedCount + ' ausgewählte in den Warenkorb';
            } else if (orderableCount > 0) {
                addAllResultsBtn.textContent = orderableCount + ' Artikel in den Warenkorb';
            } else {
                addAllResultsBtn.textContent = 'Alle Ergebnisse in den Warenkorb';
            }

            if (rowCount) {
                cartInfo.textContent = rowCount + ' Position(en) in der Ergebnisliste';
            } else {
                cartInfo.textContent = 'Ergebnisliste bereit';
            }
        }

        function setLoading(isLoading, message) {
            loadingOverlay.hidden = !isLoading;

            if (message) {
                loadingText.textContent = message;
            }
        }

        function closeAllNotePopovers(exceptRow) {
            document.querySelectorAll('.baf-note-popover').forEach(function (popover) {
                if (exceptRow && exceptRow.contains(popover)) {
                    return;
                }

                popover.hidden = true;
            });
        }

        function applyRowNoteState(row) {
            const note = String(row.dataset.note || '').trim();
            const btn = row.querySelector('.baf-note-btn');

            if (!btn) {
                return;
            }

            if (note) {
                btn.classList.add('has-note');
                btn.setAttribute('title', note);
            } else {
                btn.classList.remove('has-note');
                btn.setAttribute('title', 'Notiz hinzufügen');
            }
        }

        function setStatus(message) {
            statusBox.textContent = message;
        }
    });
})();
